<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> incsearch</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           &quot; 输入搜索内容时实时高亮</span></span>
